func (m Type) MarshalJSON() ([]byte, error) {
	type Alias Type
	return json.Marshal(&struct {
		Alias
		Type		string		`json:"type"`
		String		string		`json:"string"`
		Suffixes	[]string	`json:"suffixes"`
	}{
		Alias:		(Alias)(m),
		Type:		m.Type,
		String:		m.String(),
		Suffixes:	strings.Split(m.SuffixesCSV, ","),
	})
}
